def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 1e6 + (ratio - 2) * 1e4
        elif ratio > 1:
            priorities[i] = 1000 + (ratio - 1) * 1000
        else:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / (j ** 2)
                if j % 2 == 0:
                    term *= 1.5
                score += term
            if capacity < item * 1.2:
                score *= 3
            elif capacity < item * 1.8:
                score *= 1.5
            if ratio < 0.5:
                score -= 0.1
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = max_priority + 500
        elif priorities[i] < min_priority * 0.5:
            priorities[i] = min_priority * 0.5
    for _ in range(len(priorities)):
        for i in range(len(priorities) - 1):
            if priorities[i] > priorities[i + 1]:
                priorities[i], priorities[i + 1] = priorities[i + 1], priorities[i]
    return priorities
